args.sparql:
SELECT ?player ?birthYear WHERE {
  ?tournament wdt:P2046 wd:Q1809901;
            rdfs:label "Masters"@en.
  ?tournament wdt:P397 ?player.
  ?player wdt:P569 ?birth.
  BIND(YEAR(?birth) AS ?birthYear)
} ORDER BY DESC(?birthYear) OFFSET 3 LIMIT 1

SELECT ?player ?birthYear WHERE {
  ?event wdt:P31 wd:Q372482;
         wdt:P585 ?eventDate.
  FILTER(YEAR(?eventDate) = 2002).
  ?event wdt:P397 ?player.
  ?player wdt:P569 ?birth.
  BIND(YEAR(?birth) AS ?birthYear)
} ORDER BY DESC(?birthYear) OFFSET 3 LIMIT 1

SELECT ?player ?birthYear WHERE {
  ?tournament wdt:P31 wd:Q154256;
              rdfs:label ?label;
              wdt:P585 ?date.
  FILTER(LANG(?label) = 'en' && CONTAINS(STR(?label), 'Masters')).
  FILTER(YEAR(?date) = 2002).
  ?tournament wdt:P397 ?player.
  ?player wdt:P569 ?birth.
  BIND(YEAR(?birth) AS ?birthYear)
} ORDER BY DESC(?birthYear) OFFSET 3 LIMIT 1

